    //MSPI-8542 Set the default active menu
    var spPageGR = new GlideRecord('sp_page');
    spPageGR.get('id', data.page_id);
    data.page_sys_id = spPageGR.getValue("sys_id");

    var spRectGR = new GlideRecord("sp_rectangle_menu_item");
    spRectGR.addActiveQuery();
    //If rectangle menu item sys_id is defined and use_menu_id is true, proceed to query with the sys_id rather than page's sys_id
    if (useMenuId) {
        spRectGR.addQuery("sys_id", menuSysId);
    } else {
        spRectGR.addQuery("sp_page", data.page_sys_id);
    }
    spRectGR.query();
    if (spRectGR.next()) {
        var item = spRectGR;
        var sys_id = item.sys_id;
        while (item.sp_rectangle_menu_item) {

            item = item.sp_rectangle_menu_item;
            sys_id = item.sys_id;
        }

        data.defaultMenu = sys_id.toString();
    }

    //MSPI-8775 Fix main menu category selected state issues
    var parentChildMenus = [];
    for (var i = 0; i < data.menu.items.length; i++) {

        if (data.menu.items[i].items.length == 0) {
            var obj = {};
            obj.parent = data.menu.items[i].sys_id;
            obj.child = data.menu.items[i].sys_id;
            parentChildMenus.push(obj);
        } else {
            for (var j = 0; j < data.menu.items[i].items.length; j++) {
                if (data.menu.items[i].items[j].items.length > 0) {
                    for (var x = 0; x < data.menu.items[i].items[j].items.length; x++) {
                        if (data.menu.items[i].items[j].items[x].url_target != '_blank') {
                            var obj2 = {};
                            obj2.parent = data.menu.items[i].sys_id;
                            obj2.child = data.menu.items[i].items[j].items[x].sys_id;
                            parentChildMenus.push(obj2);
                        }
                    }
                }
            }

        }

    }
    data.parentChildMenus = parentChildMenus;


